private const string Alphabet = "0123...XYZabc...xyz"; // 62 symbols
public static string Encode(long id) {
    if (id == 0) return "0";
    var sb = new StringBuilder();
    while (id > 0) {
        sb.Insert(0, Alphabet[(int)(id % 62)]);
        id /= 62;
    }
    return sb.ToString();
}
